import numpy as np

# {This algorithm dynamically prioritizes nodes based on a real-time weighted score that combines inverse distance, path complexity (variation in adjacent node distances), and strategic points in grid-like structures, encouraging visits to nodes with unique positional advantages.}
def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        if current_node != depot_node:
            return depot_node
        return None

    node_scores = {}

    for node in unvisited_nodes:
        inverse_distance_score = 1 / (distance_matrix[current_node, node] + 1)
        path_complexity_score = np.std([distance_matrix[node, other] for other in unvisited_nodes if other != node])
        strategic_position_score = -1 if node in truck_nodes else 0

        score = inverse_distance_score + path_complexity_score + strategic_position_score
        node_scores[node] = score

    # Choose the node with the highest score
    next_node = max(node_scores, key=node_scores.get, default=None)

    return next_node

