import numpy as np

# {In this new algorithm, select the next node by generating a decision score that inversely weights the farthest unvisited node's distance while enhancing node selection by considering both the average distance from all unvisited nodes and how frequently each node is selected by other trucks, aiming to achieve a balance between dispersal and efficiency.}

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node if current_node != depot_node else None

    decision_scores = []

    truck_node_counts = {node: np.sum(truck_nodes == node) for node in unvisited_nodes}

    for node in unvisited_nodes:
        distance_to_current = distance_matrix[current_node, node]
        average_distance = np.mean([distance_matrix[node, other] for other in unvisited_nodes if other != node])
        selection_weight = truck_node_counts[node]

        decision_score = (1 / (distance_to_current + 1e-5)) * (1 + average_distance / (np.max(distance_matrix) + 1)) / (1 + selection_weight)
        decision_scores.append((decision_score, node))

    decision_scores.sort(reverse=True)
    _, next_node = decision_scores[0]

    return next_node
